import React, { useState } from "react";
import { useStats, useDoctors, useAppointments } from "../hooks";
import Modal from "../components/Modal";
import BookAppointmentForm from "../components/BookAppointmentForm";
import Toast from "../components/Toast";
import { formatSlot } from "../utils/helpers";
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer } from "recharts";

export default function Dashboard() {
  const stats = useStats();
  const { doctors } = useDoctors();
  const { appointments } = useAppointments();
  const [bookOpen, setBookOpen] = useState(false);
  const [toast, setToast] = useState(null);

  // Per-doctor appointment count
  const chartData = doctors.map((d) => ({
    name: d.name.replace("Dr. ", ""),
    count: appointments.filter((a) => a.doctor_id === d.id).length,
  }));

  const statCards = [
    { label: "Total Doctors", value: stats.total_doctors, icon: "👨‍⚕️", color: "#00bcd4" },
    { label: "Today's Appointments", value: stats.appointments_today, icon: "📅", color: "#00e5b0" },
    { label: "Upcoming", value: stats.upcoming_appointments, icon: "⏳", color: "#7c4dff" },
  ];

  return (
    <div>
      <div style={{ marginBottom: 32 }}>
        <h1 style={{ fontFamily: "'Syne', sans-serif", fontSize: 32, color: "#e0f7fa", margin: 0 }}>
          Dashboard
        </h1>
        <p style={{ color: "#546e7a", fontFamily: "'DM Mono', monospace", marginTop: 6 }}>
          Healthcare Appointment Overview
        </p>
      </div>

      {/* Stat Cards */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 20, marginBottom: 36 }}>
        {statCards.map((s) => (
          <div key={s.label} style={{
            background: "#060f1a",
            border: "1px solid #0d3a5c",
            borderRadius: 14,
            padding: "28px 24px",
            position: "relative",
            overflow: "hidden",
          }}>
            <div style={{ position: "absolute", top: 16, right: 20, fontSize: 36, opacity: 0.15 }}>{s.icon}</div>
            <p style={{ color: "#546e7a", fontFamily: "'DM Mono', monospace", fontSize: 11, letterSpacing: 1, textTransform: "uppercase", margin: "0 0 12px" }}>
              {s.label}
            </p>
            <p style={{ color: s.color, fontFamily: "'Syne', sans-serif", fontSize: 44, fontWeight: 800, margin: 0, lineHeight: 1 }}>
              {s.value}
            </p>
          </div>
        ))}
      </div>

      {/* Quick Book + Chart Row */}
      <div style={{ display: "grid", gridTemplateColumns: "1fr 2fr", gap: 20, marginBottom: 36 }}>
        {/* Quick Book */}
        <div style={{
          background: "#060f1a",
          border: "1px dashed #0d3a5c",
          borderRadius: 14,
          padding: "28px 24px",
          display: "flex",
          flexDirection: "column",
          alignItems: "flex-start",
          justifyContent: "center",
          gap: 16,
        }}>
          <p style={{ color: "#78909c", fontFamily: "'DM Mono', monospace", fontSize: 13, margin: 0 }}>
            Need to schedule a visit?
          </p>
          <h3 style={{ color: "#e0f7fa", fontFamily: "'Syne', sans-serif", fontSize: 20, margin: 0 }}>
            Quick Book
          </h3>
          <button
            onClick={() => setBookOpen(true)}
            style={{
              background: "linear-gradient(135deg, #006080, #00bcd4)",
              border: "none",
              borderRadius: 9,
              padding: "11px 24px",
              color: "#fff",
              fontFamily: "'Syne', sans-serif",
              fontWeight: 700,
              fontSize: 14,
              cursor: "pointer",
              letterSpacing: 0.5,
            }}
          >
            + Book Appointment
          </button>
        </div>

        {/* Chart */}
        <div style={{ background: "#060f1a", border: "1px solid #0d3a5c", borderRadius: 14, padding: "24px" }}>
          <p style={{ color: "#546e7a", fontFamily: "'DM Mono', monospace", fontSize: 11, letterSpacing: 1, textTransform: "uppercase", margin: "0 0 16px" }}>
            Appointments Per Doctor
          </p>
          <ResponsiveContainer width="100%" height={160}>
            <BarChart data={chartData}>
              <XAxis dataKey="name" tick={{ fill: "#546e7a", fontSize: 11 }} axisLine={false} tickLine={false} />
              <YAxis allowDecimals={false} tick={{ fill: "#546e7a", fontSize: 11 }} axisLine={false} tickLine={false} />
              <Tooltip
                contentStyle={{ background: "#020810", border: "1px solid #0d3a5c", borderRadius: 8, fontFamily: "'DM Mono', monospace", color: "#cfd8dc" }}
                cursor={{ fill: "rgba(0,188,212,0.05)" }}
              />
              <Bar dataKey="count" fill="#00bcd4" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Recent Appointments */}
      <div style={{ background: "#060f1a", border: "1px solid #0d3a5c", borderRadius: 14, padding: "24px" }}>
        <p style={{ color: "#546e7a", fontFamily: "'DM Mono', monospace", fontSize: 11, letterSpacing: 1, textTransform: "uppercase", margin: "0 0 16px" }}>
          Recent Appointments
        </p>
        {appointments.length === 0 ? (
          <p style={{ color: "#263238", fontFamily: "'DM Mono', monospace", textAlign: "center", padding: "24px 0" }}>
            No appointments yet.
          </p>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            {[...appointments].slice(-5).reverse().map((a) => (
              <div key={a.id} style={{
                display: "flex", justifyContent: "space-between", alignItems: "center",
                padding: "10px 14px", background: "#020810", borderRadius: 8,
                border: "1px solid #0d2e48",
              }}>
                <span style={{ color: "#90a4ae", fontFamily: "'DM Mono', monospace", fontSize: 13 }}>
                  {a.patient_name}
                </span>
                <span style={{ color: "#00bcd4", fontFamily: "'DM Mono', monospace", fontSize: 12 }}>
                  {a.doctor?.name || `Doctor #${a.doctor_id}`}
                </span>
                <span style={{ color: "#546e7a", fontFamily: "'DM Mono', monospace", fontSize: 12 }}>
                  {formatSlot(a.slot)}
                </span>
              </div>
            ))}
          </div>
        )}
      </div>

      <Modal isOpen={bookOpen} onClose={() => setBookOpen(false)} title="Book Appointment">
        <BookAppointmentForm
          onSuccess={() => {
            setBookOpen(false);
            setToast({ message: "Appointment booked successfully!", type: "success" });
          }}
        />
      </Modal>

      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </div>
  );
}
